  1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement, Tooltip } from '@patternfly/react-core';
  2	import * as _ from 'lodash';
  3	import * as React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { dateFormatter, getFormattedDate, getTimeRangeOptions, timeFormatter, TimeRange } from '../../utils/datetime';
  6	import {
  7	  formatDuration,
  8	  getDateFromSecondsString,
  9	  getDateMsInSeconds,
 10	  getDateSInMiliseconds,
 11	  parseDuration
 12	} from '../../utils/duration';
 13	export interface TimeRangeDropdownProps {
 14	  range: number | TimeRange;
 15	  setRange: (v: number) => void;
 16	  openCustomModal: () => void;
 17	  id?: string;
 18	}
 19	
 20	export const customTimeRangeKey = 'CUSTOM_TIME_RANGE_KEY';
 21	
 22	export const TimeRangeDropdown: React.FC<TimeRangeDropdownProps> = ({ id, range, setRange, openCustomModal }) => {
 23	  const [isOpen, setOpen] = React.useState<boolean>(false);
 24	  const { t } = useTranslation('plugin__netobserv-plugin');
 25	
 26	  const onChange = React.useCallback(
 27	    (v: string) => {
 28	      if (v === customTimeRangeKey) {
 29	        openCustomModal();
 30	      } else {
 31	        setRange(getDateMsInSeconds(parseDuration(v)));
 32	      }
 33	    },
 34	    [setRange, openCustomModal]
 35	  );
 36	
 37	  const timeRangeOptions = getTimeRangeOptions(t);
 38	  const selectedKey = typeof range !== 'number' ? customTimeRangeKey : formatDuration(getDateSInMiliseconds(range));
 39	
 40	  const textContent = (prettyPrint = true) => {
 41	    if (selectedKey === customTimeRangeKey) {
 42	      const timeRange = range as TimeRange;
 43	      const from = getDateFromSecondsString(timeRange.from?.toString());
 44	      const fromText = getFormattedDate(from);
 45	
 46	      const to = getDateFromSecondsString(timeRange.to?.toString());
 47	      let toText = getFormattedDate(to);
 48	      if (prettyPrint) {
 49	        return (
 50	          <div>
 51	            <p>{`${t('From')} ${fromText}`}</p>
 52	            <p>{`${t('To')} ${toText}`}</p>
 53	          </div>
 54	        );
 55	      } else {
 56	        //remove common part of date if possible
 57	        if (getFormattedDate(from, dateFormatter) === getFormattedDate(to, dateFormatter)) {
 58	          toText = getFormattedDate(to, timeFormatter);
 59	        }
 60	        return `${fromText} - ${toText}`;
 61	      }
 62	    } else {
 63	      return;
 64	    }
 65	  };
 66	
 67	  return (
 68	    <Tooltip
 69	      trigger={selectedKey === customTimeRangeKey ? 'mouseenter focus' : ''}
 70	      position="top"
 71	      content={textContent()}
 72	    >
 73	      <Dropdown
 74	        data-test={id}
 75	        id={id}
 76	        isOpen={isOpen}
 77	        onSelect={() => setOpen(false)}
 78	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 79	          <MenuToggle
 80	            ref={toggleRef}
 81	            data-test={`${id}-dropdown`}
 82	            id={`${id}-dropdown`}
 83	            onClick={() => setOpen(!isOpen)}
 84	            onBlur={() => setTimeout(() => setOpen(false), 500)}
 85	          >
 86	            {selectedKey === customTimeRangeKey
 87	              ? textContent(false)
 88	              : timeRangeOptions[selectedKey as keyof typeof timeRangeOptions]}
 89	          </MenuToggle>
 90	        )}
 91	      >
 92	        {_.map(timeRangeOptions, (name, key) => (
 93	          <DropdownItem data-test={key} id={key} component="button" key={key} onClick={() => onChange(key)}>
 94	            {name}
 95	          </DropdownItem>
 96	        ))}
 97	      </Dropdown>
 98	    </Tooltip>
 99	  );
100	};
101	
102	export default TimeRangeDropdown;

